use "./engines/zig.vaked"

runtime "operator-field" {
  systems = ["x86_64-linux", "aarch64-linux"]

  # Daemon-channel namespaces declared for this runtime (RFC 0017, D3: runtime-scoped).
  namespace agentGuardd { member ringbuf }
  namespace agentpipe   { member transcripts  member screenrec }

// fleet-governance.vaked — Vaked capability-graph for CI agent fleet
// Genesis Seal: 7c242080
// Grammar: v0.5 (trust, quorum, probe)
// All agents governed by capability declarations.
// No agent runs without explicit authorization.

runtime fleet {

  // ── Namespace: GitHub Actions environmen

# W-EGRESS-UNREFINED: node holds network.egress with no refining membrane.
runtime "egress-unrefined" {
  systems = ["x86_64-linux"]
  mesh m {
    node worker { role = "w" capabilities = [network.egress] }
  }
}

# E-EGRESS-USE: membrane allows public egress for a loopback-only principal.
runtime "egress-exceeds" {
  systems = ["x86_64-linux"]
  mesh m {
    node operator { role = "control" capabilities = [network.loopback] }
    node worker   { role = "w" capabilities = [network.loopback] }
    operator ->

# E-EGRESS-USE: membrane principal names no node in the mesh.
runtime "egress-bad-principal" {
  systems = ["x86_64-linux"]
  mesh m {
    node operator { role = "control" capabilities = [network.loopback] }
    node worker   { role = "w" capabilities = [network.loopback] }
    operator -> worker

